/**
 * MMS Fallback Optimizer Tests
 *
 * Unit tests for the TypeScript greedy fallback optimizer.
 * Tests constraint validation, assignment logic, and explanation generation.
 *
 * @see specs/004-domain-services.md Section 4.3
 */

import { describe, it, expect, beforeEach } from 'bun:test';
import { FallbackOptimizer } from './fallback';
import {
  type OptimizerFullInput,
  type OptimizerTrainInput,
  type OptimizerRouteInput,
  DEFAULT_OPTIMIZER_CONFIG,
} from './types';

// =============================================================================
// Test Fixtures
// =============================================================================

function createTestTrain(overrides: Partial<OptimizerTrainInput> = {}): OptimizerTrainInput {
  return {
    id: crypto.randomUUID(),
    trainNumber: 'T001',
    fleetId: 'fleet-1',
    currentMileageKm: 100000,
    targetMileageKm: 150000,
    fitnessStatus: 'FIT',
    restrictions: [],
    homeDepotId: 'depot-1',
    currentDepotId: 'depot-1',
    ...overrides,
  };
}

function createTestRoute(overrides: Partial<OptimizerRouteInput> = {}): OptimizerRouteInput {
  return {
    id: crypto.randomUUID(),
    routeCode: 'R01',
    expectedKmPerDay: 250,
    requiredTrains: 1,
    allowedFleetIds: [],
    restrictions: [],
    ...overrides,
  };
}

function createTestInput(overrides: Partial<OptimizerFullInput> = {}): OptimizerFullInput {
  return {
    requestId: crypto.randomUUID(),
    assignmentDate: '2026-01-20',
    config: DEFAULT_OPTIMIZER_CONFIG,
    trains: [createTestTrain()],
    routes: [createTestRoute()],
    hardConstraints: [],
    softConstraints: [],
    ...overrides,
  };
}

// =============================================================================
// Test Suite
// =============================================================================

describe('FallbackOptimizer', () => {
  let optimizer: FallbackOptimizer;

  beforeEach(() => {
    optimizer = new FallbackOptimizer();
  });

  describe('Basic Assignment', () => {
    it('should assign a single fit train to a single route', async () => {
      const input = createTestInput();

      const result = await optimizer.optimize(input);

      expect(result.type).toBe('RESULT');
      expect(result.status).toBe('FALLBACK');
      expect(result.assignments).toHaveLength(1);
      expect(result.assignments[0].trainId).toBe(input.trains[0].id);
      expect(result.assignments[0].routeId).toBe(input.routes[0].id);
      expect(result.unassigned).toHaveLength(0);
    });

    it('should assign multiple trains to multiple routes', async () => {
      const train1 = createTestTrain({ trainNumber: 'T001' });
      const train2 = createTestTrain({ trainNumber: 'T002' });
      const train3 = createTestTrain({ trainNumber: 'T003' });
      const route1 = createTestRoute({ routeCode: 'R01', requiredTrains: 2 });
      const route2 = createTestRoute({ routeCode: 'R02', requiredTrains: 1 });

      const input = createTestInput({
        trains: [train1, train2, train3],
        routes: [route1, route2],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(3);
      expect(result.summary.trainsAssigned).toBe(3);
      expect(result.summary.trainsUnassigned).toBe(0);
    });

    it('should report unassigned trains when routes are fully staffed', async () => {
      const train1 = createTestTrain({ trainNumber: 'T001' });
      const train2 = createTestTrain({ trainNumber: 'T002' });
      const route = createTestRoute({ requiredTrains: 1 });

      const input = createTestInput({
        trains: [train1, train2],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.unassigned.length).toBeGreaterThanOrEqual(1);
      expect(result.summary.trainsUnassigned).toBe(1);
    });

    it('should report route shortfall when not enough trains available', async () => {
      const train = createTestTrain();
      const route = createTestRoute({ requiredTrains: 3 });

      const input = createTestInput({
        trains: [train],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.unassigned.some((u) => u.routeId === route.id)).toBe(true);
      expect(result.unassigned.find((u) => u.routeId === route.id)?.shortfall).toBe(2);
    });
  });

  describe('Fitness Status Constraints', () => {
    it('should not assign GROUNDED trains', async () => {
      const groundedTrain = createTestTrain({ fitnessStatus: 'GROUNDED' });
      const route = createTestRoute();

      const input = createTestInput({
        trains: [groundedTrain],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
      expect(result.unassigned).toHaveLength(2); // train + route shortfall
      expect(result.unassigned.some((u) => u.trainId === groundedTrain.id)).toBe(true);
    });

    it('should not assign RESTRICTED trains', async () => {
      const restrictedTrain = createTestTrain({ fitnessStatus: 'RESTRICTED' });
      const route = createTestRoute();

      const input = createTestInput({
        trains: [restrictedTrain],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
      expect(result.unassigned.some((u) => u.trainId === restrictedTrain.id)).toBe(true);
    });

    it('should only assign FIT trains', async () => {
      const fitTrain = createTestTrain({ fitnessStatus: 'FIT', trainNumber: 'T001' });
      const groundedTrain = createTestTrain({ fitnessStatus: 'GROUNDED', trainNumber: 'T002' });
      const restrictedTrain = createTestTrain({ fitnessStatus: 'RESTRICTED', trainNumber: 'T003' });
      const route = createTestRoute({ requiredTrains: 3 });

      const input = createTestInput({
        trains: [fitTrain, groundedTrain, restrictedTrain],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.assignments[0].trainId).toBe(fitTrain.id);
    });
  });

  describe('Unavailability Events', () => {
    it('should not assign trains with active blocking unavailability', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        unavailabilityEvents: [
          {
            trainId: train.id,
            eventType: 'CORRECTIVE',
            status: 'ACTIVE',
            blocksRunAssignment: true,
            description: 'Engine failure',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
      expect(result.unassigned.some((u) => u.trainId === train.id)).toBe(true);
      expect(result.unassigned.find((u) => u.trainId === train.id)?.reason).toContain('Unavailable');
    });

    it('should assign trains with resolved unavailability', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        unavailabilityEvents: [
          {
            trainId: train.id,
            eventType: 'CORRECTIVE',
            status: 'RESOLVED',
            blocksRunAssignment: true,
            description: 'Engine failure fixed',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.assignments[0].trainId).toBe(train.id);
    });

    it('should assign trains with non-blocking unavailability', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        unavailabilityEvents: [
          {
            trainId: train.id,
            eventType: 'CORRECTIVE',
            status: 'ACTIVE',
            blocksRunAssignment: false,
            description: 'Minor issue',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
    });
  });

  describe('Hard Constraints', () => {
    it('should not assign trains with hard constraints', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        hardConstraints: [
          {
            type: 'PM_DUE',
            trainId: train.id,
            description: 'C4 maintenance due today',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
      expect(result.unassigned.some((u) => u.trainId === train.id)).toBe(true);
    });

    it('should assign trains without hard constraints', async () => {
      const train1 = createTestTrain({ trainNumber: 'T001' });
      const train2 = createTestTrain({ trainNumber: 'T002' });
      const route = createTestRoute({ requiredTrains: 2 });

      const input = createTestInput({
        trains: [train1, train2],
        routes: [route],
        hardConstraints: [
          {
            type: 'PM_DUE',
            trainId: train1.id,
            description: 'C4 maintenance due',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.assignments[0].trainId).toBe(train2.id);
    });
  });

  describe('Route Compatibility', () => {
    it('should not assign trains incompatible with route', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        routeCompatibility: [
          {
            trainId: train.id,
            routeId: route.id,
            isCompatible: false,
            constraintType: 'SIGNALING',
            restrictionReason: 'ATO system incompatible',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
    });

    it('should assign trains compatible with route', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        routeCompatibility: [
          {
            trainId: train.id,
            routeId: route.id,
            isCompatible: true,
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
    });
  });

  describe('Fleet Compatibility', () => {
    it('should only assign trains from allowed fleets', async () => {
      const train1 = createTestTrain({ fleetId: 'fleet-1', trainNumber: 'T001' });
      const train2 = createTestTrain({ fleetId: 'fleet-2', trainNumber: 'T002' });
      const route = createTestRoute({ allowedFleetIds: ['fleet-1'] });

      const input = createTestInput({
        trains: [train1, train2],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.assignments[0].trainId).toBe(train1.id);
    });

    it('should assign any fleet when no restriction specified', async () => {
      const train = createTestTrain({ fleetId: 'any-fleet' });
      const route = createTestRoute({ allowedFleetIds: [] });

      const input = createTestInput({
        trains: [train],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
    });
  });

  describe('Mileage Balancing', () => {
    it('should prioritize under-utilized trains', async () => {
      const underUtilized = createTestTrain({
        trainNumber: 'T001',
        currentMileageKm: 50000,
        targetMileageKm: 100000, // 50k under target
      });
      const overUtilized = createTestTrain({
        trainNumber: 'T002',
        currentMileageKm: 150000,
        targetMileageKm: 100000, // 50k over target
      });
      const route = createTestRoute({ requiredTrains: 1 });

      const input = createTestInput({
        trains: [overUtilized, underUtilized], // Order shouldn't matter
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(1);
      expect(result.assignments[0].trainId).toBe(underUtilized.id);
    });

    it('should generate mileage balance explanations', async () => {
      const train = createTestTrain({
        currentMileageKm: 80000,
        targetMileageKm: 100000, // 20k under target
      });
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments[0].explanation).toHaveLength(1);
      expect(result.assignments[0].explanation[0].constraintName).toBe('MILEAGE_BALANCE');
      expect(result.assignments[0].explanation[0].description).toContain('under target');
    });
  });

  describe('Service Demand Validation', () => {
    it('should report service demand violations', async () => {
      const train = createTestTrain({ fleetId: 'fleet-1' });
      const route = createTestRoute({ requiredTrains: 1 });

      const input = createTestInput({
        trains: [train],
        routes: [route],
        serviceDemand: [
          {
            fleetId: 'fleet-1',
            minTrainsRequired: 5, // More than available
            dayType: 'WEEKDAY',
          },
        ],
      });

      const result = await optimizer.optimize(input);

      // Should still assign available trains
      expect(result.assignments).toHaveLength(1);
      // But also report the service demand violation
      expect(result.unassigned.some((u) => u.reason.includes('Service demand violation'))).toBe(true);
    });
  });

  describe('Material Warnings', () => {
    it('should generate material warnings for pending PMs', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        pendingPms: [
          {
            pmId: 'pm-1',
            trainId: train.id,
            pmType: 'C4',
            targetDate: '2026-01-25', // Within 14 days
            requiredMaterials: [
              {
                partNumber: 'PART-001',
                quantity: 2,
                criticality: 'BLOCKING',
              },
            ],
          },
        ],
        materialPositions: [
          {
            depotId: train.homeDepotId,
            partNumber: 'PART-001',
            quantityAvailable: 1, // Not enough
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.materialWarnings).toHaveLength(1);
      expect(result.materialWarnings[0].partNumber).toBe('PART-001');
      expect(result.materialWarnings[0].status).toBe('LOW_STOCK');
    });

    it('should not warn about non-blocking materials', async () => {
      const train = createTestTrain();
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
        pendingPms: [
          {
            pmId: 'pm-1',
            trainId: train.id,
            pmType: 'C4',
            targetDate: '2026-01-25',
            requiredMaterials: [
              {
                partNumber: 'PART-001',
                quantity: 2,
                criticality: 'DEFERRABLE', // Not blocking
              },
            ],
          },
        ],
        materialPositions: [
          {
            depotId: train.homeDepotId,
            partNumber: 'PART-001',
            quantityAvailable: 0,
          },
        ],
      });

      const result = await optimizer.optimize(input);

      expect(result.materialWarnings).toHaveLength(0);
    });
  });

  describe('Explanation Verbosity', () => {
    it('should include depot preference in explanations', async () => {
      const train = createTestTrain({
        homeDepotId: 'depot-1',
        currentDepotId: 'depot-2', // Away from home
      });
      const route = createTestRoute();

      const input = createTestInput({
        trains: [train],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      const depotExplanation = result.assignments[0].explanation.find(
        (e) => e.constraintName === 'DEPOT_PREFERENCE'
      );
      expect(depotExplanation).toBeDefined();
      expect(depotExplanation?.description).toContain('away from home depot');
    });

    it('should include detailed route info in DETAILED mode', async () => {
      const train = createTestTrain();
      const route = createTestRoute({ expectedKmPerDay: 300 });

      const input = createTestInput({
        trains: [train],
        routes: [route],
        config: {
          ...DEFAULT_OPTIMIZER_CONFIG,
          explanationVerbosity: 'DETAILED',
        },
      });

      const result = await optimizer.optimize(input);

      const routeExplanation = result.assignments[0].explanation.find(
        (e) => e.constraintName === 'ROUTE_UTILIZATION'
      );
      expect(routeExplanation).toBeDefined();
      expect(routeExplanation?.description).toContain('300km');
    });
  });

  describe('Result Summary', () => {
    it('should calculate correct summary statistics', async () => {
      const train1 = createTestTrain({ trainNumber: 'T001' });
      const train2 = createTestTrain({ trainNumber: 'T002', fitnessStatus: 'GROUNDED' });
      const route = createTestRoute({ requiredTrains: 1 });

      const input = createTestInput({
        trains: [train1, train2],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.summary.trainsAssigned).toBe(1);
      expect(result.summary.trainsUnassigned).toBe(1);
      expect(typeof result.summary.totalPenalty).toBe('number');
      expect(result.summary.softConstraintBreakdown).toBeDefined();
    });

    it('should track solve time', async () => {
      const input = createTestInput();

      const result = await optimizer.optimize(input);

      expect(result.solveTimeMs).toBeGreaterThanOrEqual(0);
      expect(result.solveTimeMs).toBeLessThan(5000); // Should be fast
    });
  });

  describe('Edge Cases', () => {
    it('should handle empty trains list', async () => {
      const route = createTestRoute();

      const input = createTestInput({
        trains: [],
        routes: [route],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
      expect(result.unassigned.some((u) => u.routeId === route.id)).toBe(true);
    });

    it('should handle empty routes list', async () => {
      const train = createTestTrain();

      const input = createTestInput({
        trains: [train],
        routes: [],
      });

      const result = await optimizer.optimize(input);

      expect(result.assignments).toHaveLength(0);
      expect(result.unassigned.some((u) => u.trainId === train.id)).toBe(true);
    });

    it('should handle large input efficiently', async () => {
      // Create 100 trains and 20 routes
      const trains = Array.from({ length: 100 }, (_, i) =>
        createTestTrain({
          trainNumber: `T${String(i + 1).padStart(3, '0')}`,
          currentMileageKm: 50000 + i * 1000,
        })
      );

      const routes = Array.from({ length: 20 }, (_, i) =>
        createTestRoute({
          routeCode: `R${String(i + 1).padStart(2, '0')}`,
          requiredTrains: 5,
        })
      );

      const input = createTestInput({
        trains,
        routes,
      });

      const startTime = Date.now();
      const result = await optimizer.optimize(input);
      const elapsedMs = Date.now() - startTime;

      expect(result.assignments.length).toBe(100);
      expect(elapsedMs).toBeLessThan(1000); // Should complete in < 1 second
    });
  });
});

